{"title":"Pipestream / Throughput per instance","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Docs completed per minute, by service_instance_id",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "event_timestamp",
      "index": "pipeline-events-*",
      "body": {
        "size": 0,
        "aggs": {
          "by_instance": {
            "terms": { "field": "service_instance_id", "size": 50, "missing": "(unknown)" },
            "aggs": {
              "over_time": {
                "date_histogram": { "field": "event_timestamp", "fixed_interval": "1m", "min_doc_count": 0 },
                "aggs": { "docs": { "cardinality": { "field": "document_id", "precision_threshold": 4000 } } }
              }
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.by_instance.buckets" }
  },
  "transform": [
    { "flatten": ["over_time.buckets"], "as": ["bucket"] },
    { "calculate": "datum.bucket.key", "as": "ts" },
    { "calculate": "datum.bucket.docs.value", "as": "docs" }
  ],
  "mark": { "type": "line", "point": true, "interpolate": "monotone" },
  "encoding": {
    "x": { "field": "ts", "type": "temporal", "title": "Time" },
    "y": { "field": "docs", "type": "quantitative", "title": "Distinct docs / minute" },
    "color": { "field": "key", "type": "nominal", "title": "Engine instance" },
    "tooltip": [
      { "field": "key", "type": "nominal", "title": "instance" },
      { "field": "ts", "type": "temporal", "title": "time" },
      { "field": "docs", "type": "quantitative", "title": "docs/min" }
    ]
  }
}"}}

{"title":"Pipestream / Step latency p50/p95/p99","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Latency percentiles per module (ms)",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "event_timestamp",
      "index": "pipeline-events-*",
      "body": {
        "size": 0,
        "query": { "bool": { "filter": [ { "terms": { "status": ["SUCCESS", "PARTIAL"] } } ] } },
        "aggs": {
          "by_module": {
            "terms": { "field": "module_id", "size": 50, "order": { "p95>95": "desc" } },
            "aggs": {
              "p50": { "percentiles": { "field": "duration_ms", "percents": [50] } },
              "p95": { "percentiles": { "field": "duration_ms", "percents": [95] } },
              "p99": { "percentiles": { "field": "duration_ms", "percents": [99] } }
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.by_module.buckets" }
  },
  "transform": [
    { "calculate": "datum.p50.values['50.0']", "as": "p50_v" },
    { "calculate": "datum.p95.values['95.0']", "as": "p95_v" },
    { "calculate": "datum.p99.values['99.0']", "as": "p99_v" },
    { "fold": ["p50_v", "p95_v", "p99_v"], "as": ["percentile", "value"] },
    { "calculate": "datum.percentile == 'p50_v' ? 'p50' : datum.percentile == 'p95_v' ? 'p95' : 'p99'", "as": "pctl" }
  ],
  "mark": "bar",
  "encoding": {
    "y": { "field": "key", "type": "nominal", "title": "module_id", "sort": "-x" },
    "x": { "field": "value", "type": "quantitative", "title": "duration_ms" },
    "yOffset": { "field": "pctl", "type": "nominal" },
    "color": { "field": "pctl", "type": "nominal", "title": "percentile", "scale": { "domain": ["p50", "p95", "p99"], "range": ["#7FB3D5", "#F5B041", "#E74C3C"] } },
    "tooltip": [
      { "field": "key", "type": "nominal", "title": "module" },
      { "field": "pctl", "type": "nominal", "title": "percentile" },
      { "field": "value", "type": "quantitative", "title": "ms" }
    ]
  }
}"}}

{"title":"Pipestream / PARTIAL rate per module","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "PARTIAL rate per module (0.0 = clean, 1.0 = every call partial)",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "event_timestamp",
      "index": "pipeline-events-*",
      "body": {
        "size": 0,
        "aggs": {
          "by_module": {
            "terms": { "field": "module_id", "size": 50 },
            "aggs": {
              "partial_count": { "filter": { "term": { "status": "PARTIAL" } } },
              "total": { "value_count": { "field": "status" } },
              "partial_rate": { "bucket_script": { "buckets_path": { "p": "partial_count._count", "t": "total" }, "script": "params.t == 0 ? 0 : params.p / params.t" } }
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.by_module.buckets" }
  },
  "transform": [
    { "calculate": "datum.partial_rate.value", "as": "rate" },
    { "calculate": "datum.partial_count.doc_count", "as": "partials" },
    { "calculate": "datum.total.value", "as": "calls" }
  ],
  "mark": "bar",
  "encoding": {
    "y": { "field": "key", "type": "nominal", "title": "module_id", "sort": "-x" },
    "x": { "field": "rate", "type": "quantitative", "title": "PARTIAL rate", "axis": { "format": ".0%" } },
    "color": { "field": "rate", "type": "quantitative", "scale": { "scheme": "orangered", "domain": [0, 0.25] }, "legend": null },
    "tooltip": [
      { "field": "key", "type": "nominal", "title": "module" },
      { "field": "rate", "type": "quantitative", "title": "PARTIAL rate", "format": ".2%" },
      { "field": "partials", "type": "quantitative", "title": "# partial" },
      { "field": "calls", "type": "quantitative", "title": "# total" }
    ]
  }
}"}}

{"title":"Pipestream / Slowest docs end-to-end","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Top 50 slowest docs (wall-clock e2e ms)",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "event_timestamp",
      "index": "pipeline-events-*",
      "body": {
        "size": 0,
        "aggs": {
          "by_doc": {
            "terms": { "field": "document_id", "size": 50, "order": { "e2e_ms": "desc" } },
            "aggs": {
              "first_seen": { "min": { "field": "event_timestamp" } },
              "last_seen":  { "max": { "field": "event_timestamp" } },
              "hops":       { "max": { "field": "hop_number" } },
              "step_ms_sum": { "sum": { "field": "duration_ms" } },
              "e2e_ms": { "bucket_script": { "buckets_path": { "a": "first_seen", "b": "last_seen" }, "script": "params.b - params.a" } }
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.by_doc.buckets" }
  },
  "transform": [
    { "calculate": "datum.e2e_ms.value", "as": "e2e" },
    { "calculate": "datum.step_ms_sum.value", "as": "step_sum" },
    { "calculate": "datum.hops.value", "as": "hop_count" }
  ],
  "mark": "bar",
  "encoding": {
    "y": { "field": "key", "type": "nominal", "title": "document_id", "sort": "-x" },
    "x": { "field": "e2e", "type": "quantitative", "title": "end-to-end ms" },
    "tooltip": [
      { "field": "key", "type": "nominal", "title": "document_id" },
      { "field": "e2e", "type": "quantitative", "title": "e2e ms" },
      { "field": "step_sum", "type": "quantitative", "title": "sum(step ms)" },
      { "field": "hop_count", "type": "quantitative", "title": "hops" }
    ]
  }
}"}}
